function Counter({ initial }) {
  // useState initial value is used only on mount
  // On re-renders, React ignores the argument and uses stored state
  const [count, setCount] = useState(initial);

  // Lazy initialization — the function runs only on mount
  const [data] = useState(() => heavyComputation());

  return (
    <div>
      <p>{count}</p>
      <button onClick={() => setCount(c => c + 1)}>+1</button>
    </div>
  );
}

function ItemList({ items }) {
  return (
    <ul>
      {items.map((item) => (
        // key is critical for reconciliation
        // React uses key to match new elements with previous elements
        <li key={item.id}>{item.name}</li>
      ))}
    </ul>
  );
}

function Example({ userId }) {
  // Mount: BOTH effects run, regardless of userId value
  useEffect(() => {
    console.log('analytics — always fires on mount');
  }, []); // ← empty array means mount only, never update

  useEffect(() => {
    console.log('sync with userId:', userId);
  }, [userId]); // ← mount + whenever userId changes
}

function Profile({ userId, theme }) {
  // Runs on mount AND when userId changes; skipped when only theme changes
  useEffect(() => {
    const sub = subscribeToUser(userId);
    return () => sub.unsubscribe();
  }, [userId]);

  // Runs on mount AND when theme changes; skipped when only userId changes
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);
}

// When userId changes:
// 1. Re-render (Profile fn re-executes with new userId)
// 2. First effect cleanup: unsubscribe from old userId
// 3. First effect setup: subscribe to new userId
// 4. Second effect: skipped (theme did not change)

function Form() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');

  function handleReset() {
    setName('');   // queued — no render yet
    setEmail('');  // queued — no render yet
    // React batches both: ONE re-render with name='' and email=''
  }

  async function handleSubmit() {
    await save(name, email);
    setName('');   // React 18: still batched even after await
    setEmail('');
    // ONE re-render (React 18 automatic batching for async)
  }
}

// useState bailout: same primitive → no re-render
const [count, setCount] = useState(0);
setCount(0); // already 0 → React bails out

// React.memo: same props → skip re-render of the wrapped component
const MemoChild = React.memo(function Child({ text }) {
  return <p>{text}</p>;
});

// useMemo: memoize expensive derived values
const sorted = useMemo(
  () => items.slice().sort((a, b) => a.name.localeCompare(b.name)),
  [items]
);

// Simplified mental model of a fiber node (not actual React source)
const fiber = {
  type: Counter,          // the component function
  memoizedState: {        // linked list of hook state nodes
    memoizedState: 0,     // current useState value
    queue: { pending: null }, // queued state updates
    next: null,           // next hook in this component
  },
  stateNode: domNode,     // the actual DOM node
  alternate: wipFiber,    // the work-in-progress copy during update
