function Parent() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <button onClick={() => setCount(c => c + 1)}>+1</button>
      {/* Child re-renders on every Parent render even though its props never change */}
      <Child label="Static" />
    </div>
  );
}

// Opt out of parent-triggered re-renders with React.memo
const Child = React.memo(function Child({ label }) {
  return <p>{label}</p>;
});
// Now Child only re-renders when label actually changes

// Add a render log during development to count re-renders
function DebugCounter({ name }) {
  const renders = useRef(0);
  renders.current++;
  console.log(`[RENDER] ${name} — #${renders.current}`);

  return null; // render nothing — used for debugging only
}

// Place it inside the component you suspect is over-rendering
function ProductCard({ product }) {
  return (
    <div>
      <DebugCounter name="ProductCard" />
      <h3>{product.name}</h3>
    </div>
  );
}

// Anti-pattern: syncing props into state with useEffect
function BadSort({ items }) {
  const [sorted, setSorted] = useState([...items].sort());

  useEffect(() => {
    setSorted([...items].sort());
  }, [items]);
  // This causes a double render: once with stale sorted, once after effect

  return <ul>{sorted.map(renderItem)}</ul>;
}

// Correct: derive during render, memoize if expensive
function GoodSort({ items }) {
  const sorted = useMemo(() => [...items].sort(), [items]);
  return <ul>{sorted.map(renderItem)}</ul>;
}

function ChatRoom({ roomId }) {
  const prevRoomId = useRef(roomId);

  useEffect(() => {
    // Compare current and previous roomId
    if (prevRoomId.current !== roomId) {
      logRoomChange(prevRoomId.current, roomId);
    }
    prevRoomId.current = roomId; // update after logging
  }, [roomId]);

  return <p>Room: {roomId}</p>;
}

import { flushSync } from 'react-dom';

function ScrollList({ items }) {
  const listRef = useRef(null);

  function addItem(newItem) {
    // Force synchronous render before measuring the DOM
    flushSync(() => {
      setItems((prev) => [...prev, newItem]);
    });
    // DOM is updated here — can safely read scroll height
    listRef.current.scrollTop = listRef.current.scrollHeight;
  }
}

import { useState, useTransition } from 'react';

function SearchResults({ items }) {
  const [query, setQuery] = useState('');
  const [filtered, setFiltered] = useState(items);
  const [isPending, startTransition] = useTransition();

  function handleChange(e) {
    const value = e.target.value;
    setQuery(value); // urgent — updates input immediately

    startTransition(() => {
      // non-urgent — React may defer this update
      setFiltered(items.filter((item) => item.name.includes(value)));
    });
  }

  return (
    <div>
      <input value={query} onChange={handleChange} />
      {isPending && <p>Filtering…</p>}
      <ul>{filtered.map(renderItem)}</ul>
    </div>
  );
}

class ErrorBoundary extends React.Component {
  state = { hasError: false };

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, info) {
    logErrorToService(error, info.componentStack);
  }

  render() {
    if (this.state.hasError) {
      return <p>Something went wrong.</p>;
    }
    return this.props.children;
  }
}

// Wrap any subtree that might throw
<ErrorBoundary>
  <DataChart data={maybeInvalidData} />
</ErrorBoundary>
